def verify(output):
    is_valid, score = True, 0.0

    details = {}
    if '2026' in output:
        details['2026_count'] = output.count('2026')
        if details['2026_count'] != 12:
            is_valid = False
            score = 0.0
    else:
        is_valid = False
    return is_valid, score
